// src/components/Search.js
import React, { useState } from 'react';
import axios from 'axios';

const Search = ({ onSearch }) => {
  const [district, setDistrict] = useState('');
  const [taluka, setTaluka] = useState('');
  const [village, setVillage] = useState('');
  const [surveyNo, setSurveyNo] = useState('');
  const [mobile, setMobile] = useState('');
  const [captcha, setCaptcha] = useState('');
  const [searchType, setSearchType] = useState('Survey Number');
  const [language, setLanguage] = useState('Marathi');

  const handleSearch = async () => {
    try {
      const response = await axios.get(`http://127.0.0.1:8000/api/search/`, {
        params: { query: surveyNo, district, taluka, village, mobile, captcha },
      });
      console.log("API response:", response.data);  // Log the response
      onSearch(response.data);
    } catch (error) {
      console.error("Error fetching data:", error);
    }
  };

  return (
    <div className="search-container">
      <h2>Search Land Records</h2>
      <form>
        <div className="form-group">
          <label>Do you know your 11 Digit Property UID Number?</label>
          <div>
            <label>
              <input type="radio" name="uid" value="yes" /> Yes
            </label>
            <label>
              <input type="radio" name="uid" value="no" checked /> No
            </label>
          </div>
        </div>

        <div className="form-group">
          <label>Select Record of Right</label>
          <div>
            <label>
              <input
                type="radio"
                name="recordType"
                value="7/12"
                checked
                onChange={(e) => setSearchType(e.target.value)}
              />
              7/12
            </label>
            <label>
              <input
                type="radio"
                name="recordType"
                value="8A"
                onChange={(e) => setSearchType(e.target.value)}
              />
              8A
            </label>
            <label>
              <input
                type="radio"
                name="recordType"
                value="Property Card"
                onChange={(e) => setSearchType(e.target.value)}
              />
              Property Card
            </label>
            <label>
              <input
                type="radio"
                name="recordType"
                value="K-Prat"
                onChange={(e) => setSearchType(e.target.value)}
              />
              K-Prat
            </label>
          </div>
        </div>

        <div className="form-group">
          <label>District</label>
          <select
            className="form-control"
            value={district}
            onChange={(e) => setDistrict(e.target.value)}
          >
            <option value="">--Select--</option>
            <option value="Akola">Akola</option>
            <option value="Amravati">Amravati</option>
            <option value="Buldhana">Buldhana</option>
            {/* Add more districts as required */}
          </select>
        </div>

        <div className="form-group">
          <label>Taluka</label>
          <select
            className="form-control"
            value={taluka}
            onChange={(e) => setTaluka(e.target.value)}
          >
            <option value="">--Select--</option>
            <option value="Akola Taluka">Akola Taluka</option>
            <option value="Amravati Taluka">Amravati Taluka</option>
            <option value="Buldhana Taluka">Buldhana Taluka</option>
            {/* Add more talukas as required */}
          </select>
        </div>

        <div className="form-group">
          <label>Village</label>
          <select
            className="form-control"
            value={village}
            onChange={(e) => setVillage(e.target.value)}
          >
            <option value="">--Select--</option>
            <option value="Village1">Village1</option>
            <option value="Village2">Village2</option>
            {/* Add more villages as required */}
          </select>
        </div>

        <div className="form-group">
          <label>Survey Number</label>
          <input
            type="text"
            className="form-control"
            value={surveyNo}
            onChange={(e) => setSurveyNo(e.target.value)}
            placeholder="Enter Survey Number"
          />
        </div>

        <div className="form-group">
          <label>Mobile Number</label>
          <input
            type="text"
            className="form-control"
            value={mobile}
            onChange={(e) => setMobile(e.target.value)}
            placeholder="Enter Mobile Number"
          />
        </div>

        <div className="form-group">
          <label>Captcha</label>
          <input
            type="text"
            className="form-control"
            value={captcha}
            onChange={(e) => setCaptcha(e.target.value)}
            placeholder="Enter Captcha"
          />
          {/* Include Captcha image here */}
          <img src="captcha.png" alt="Captcha" />
        </div>

        <div className="form-group">
          <label>Select Language</label>
          <select
            className="form-control"
            value={language}
            onChange={(e) => setLanguage(e.target.value)}
          >
            <option value="Marathi">Marathi</option>
            <option value="English">English</option>
            {/* Add more languages as required */}
          </select>
        </div>

        <div className="form-group">
          <button
            type="button"
            className="btn btn-success"
            onClick={handleSearch}
          >
            Search
          </button>
        </div>
      </form>
    </div>
  );
};

export default Search;
